export function exportBookingsToExcel() {
    const allBookings = state.bookings;
    if (!allBookings || allBookings.length === 0) {
        alert('Нет данных для выгрузки');
        return;
    }

    const statusLabels = { pending: 'Ожидает', confirmed: 'Подтверждена', completed: 'Завершена', cancelled: 'Отменена' };
    const headers = ['ID', 'Дата', 'Время', 'Клиент', 'Телефон', 'Услуга', 'Салон', 'Мастер', 'Стоимость', 'Комиссия %', 'Доход мастера', 'Прибыль салона', 'Статус'];
    const rows = [headers];

    allBookings.forEach(b => {
        const m = masters.find(m => m.id === b.masterId);
        const svc = services.find(s => s.id === b.serviceId);
        const salonId = m ? m.salonId : (b.type === 'salon' ? b.targetId : null);
        const salon = salons.find(s => s.id === salonId);
        
        let masterCommPct = m && svc ? lookupMasterServiceCommission(m, svc.id) : 0;
        let price = svc ? svc.price : 0;
        let masterEarn = Math.round((price * masterCommPct) / 100);
        let salonProfit = price - masterEarn;

        rows.push([
            b.id,
            b.date,
            b.time,
            `"${(b.clientName || '').replace(/"/g, '""')}"`,
            b.clientPhone,
            `"${(svc ? svc.name : '').replace(/"/g, '""')}"`,
            `"${(salon ? salon.name : '').replace(/"/g, '""')}"`,
            `"${(m ? m.name : '').replace(/"/g, '""')}"`,
            price,
            masterCommPct,
            masterEarn,
            salonProfit,
            statusLabels[b.status] || b.status
        ]);
    });

    const csvContent = rows.map(r => r.join(';')).join('\n');
    // Adding BOM for proper UTF-8 opening in Excel
    const blob = new Blob(["\uFEFF", csvContent], { type: 'text/csv;charset=utf-8;' });
    const url = URL.createObjectURL(blob);
    const link = document.createElement("a");
    link.setAttribute("href", url);
    link.setAttribute("download", "bookings_export.csv");
    document.body.appendChild(link);
    link.click();
    document.body.removeChild(link);
};

window.exportBookingsToExcel = exportBookingsToExcel;

export function updateCategoryField(id, field, value) {
    const cat = categories.find(c => c.id === id);
    if (cat) cat[field] = value;
    render();
}

window.updateCategoryField = updateCategoryField;

export function deleteCategory(id) {
    const idx = categories.findIndex(c => c.id === id);
    if (idx >= 0) categories.splice(idx, 1);
    render();
}

window.deleteCategory = deleteCategory;

export function addCategory() {
    const icon = document.getElementById('newCatIcon').value || '📋';
    const name = document.getElementById('newCatName').value;
    if (!name) return;
    const newId = categories.length ? Math.max(...categories.map(c => c.id)) + 1 : 1;
    categories.push({ id: newId, icon, name });
    render();
}

window.addCategory = addCategory;
